KotlinJava <pre><code>databaseHelper.writableDatabase.run {
    insert(
        "Foo",
        ContentValues().apply { put("bar", 42) },
        ConflictAlgorithm.REPLACE
    )
    query(false, "Foo", arrayOf("bar"), null, null).use {
        it.moveToFirst()
        println(it.getInt(0))
    }
}
</code></pre> <pre><code>final SQLiteDatabase database = databaseHelper.getWritableDatabase();
