    maxPoolSize = 5 // 1 connection for writing and 4 for reading
    foreignKeys = true
}

dataSource.connection.use { connection -&gt;
    // Use connection
}
</code></pre> <pre><code>final SelektDataSource dataSource = new SelektDataSource();
