KotlinJava <pre><code>dataSource.connection.use { connection -&gt;
    connection.prepareStatement("SELECT id, name FROM users WHERE id = ?").use { statement -&gt;
        statement.setInt(1, 42)
        statement.executeQuery().use { resultSet -&gt;
            while (resultSet.next()) {
                println("${resultSet.getInt("id")}: ${resultSet.getString("name")}")
            }
        }
    }
}
</code></pre> <pre><code>try (Connection connection = dataSource.getConnection();
     PreparedStatement statement = connection.prepareStatement(
         "SELECT id, name FROM users WHERE id = ?")) {
    statement.setInt(1, 42);
    try (ResultSet resultSet = statement.executeQuery()) {
        while (resultSet.next()) {
            System.out.println(resultSet.getInt("id") + ": " + resultSet.getString("name"));
        }
    }
}
</code></pre>

