KotlinJava <pre><code>dataSource.connection.use { connection -&gt;
    connection.autoCommit = false
    try {
        connection.prepareStatement("INSERT INTO users (id, name) VALUES (?, ?)").use { statement -&gt;
            for (i in 1..1000) {
                statement.setInt(1, i)
                statement.setString(2, "User $i")
                statement.addBatch()
            }
            statement.executeBatch()
        }
        connection.commit()
    } catch (e: SQLException) {
        connection.rollback()
        throw e
    }
}
</code></pre> <pre><code>try (Connection connection = dataSource.getConnection()) {
    connection.setAutoCommit(false);
    try (PreparedStatement statement = connection.prepareStatement(
            "INSERT INTO users (id, name) VALUES (?, ?)")) {
        for (int i = 1; i &lt;= 1000; i++) {
            statement.setInt(1, i);
            statement.setString(2, "User " + i);
            statement.addBatch();
        }
        statement.executeBatch();
        connection.commit();
    } catch (final SQLException e) {
        connection.rollback();
        throw e;
    }
}
</code></pre>

KotlinJava <pre><code>dataSource.connection.use { connection -&gt;
    connection.autoCommit = false
    try {
        connection.prepareStatement("UPDATE accounts SET balance = balance - ? WHERE id = ?").use { statement -&gt;
            statement.setDouble(1, 100.0)
            statement.setInt(2, 1)
            statement.executeUpdate()
        }
        connection.prepareStatement("UPDATE accounts SET balance = balance + ? WHERE id = ?").use { statement -&gt;
            statement.setDouble(1, 100.0)
            statement.setInt(2, 2)
            statement.executeUpdate()
        }
        connection.commit()
    } catch (e: SQLException) {
        connection.rollback()
        throw e
    }
}
</code></pre> <pre><code>try (Connection connection = dataSource.getConnection()) {
    connection.setAutoCommit(false);
    try {
        try (final PreparedStatement debit = connection.prepareStatement(
                "UPDATE accounts SET balance = balance - ? WHERE id = ?")) {
            debit.setDouble(1, 100.0);
            debit.setInt(2, 1);
            debit.executeUpdate();
        }
        try (final PreparedStatement credit = connection.prepareStatement(
                "UPDATE accounts SET balance = balance + ? WHERE id = ?")) {
            credit.setDouble(1, 100.0);
            credit.setInt(2, 2);
            credit.executeUpdate();
        }
        connection.commit();
    } catch (final SQLException e) {
        connection.rollback();
        throw e;
    }
}
</code></pre>

